/*Table structure for table `blockchain_logs` */

DROP TABLE IF EXISTS `blockchain_logs`;

CREATE TABLE `blockchain_logs` (
  `bc_id` int(11) NOT NULL AUTO_INCREMENT,
  `fid` int(11) DEFAULT NULL,
  `device_email` varchar(100) DEFAULT NULL,
  `file_hash` varchar(256) DEFAULT NULL,
  `fog_node` varchar(100) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`bc_id`),
  KEY `blockchain_logs_ibfk_1` (`fid`),
  CONSTRAINT `blockchain_logs_ibfk_1` FOREIGN KEY (`fid`) REFERENCES `uploaded_files` (`fid`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=70 DEFAULT CHARSET=latin1;

